SELECT id, user_id, username, operation, http_method, request_uri, request_ip,
       request_params, response_result, execution_time, status, error_message, create_time
FROM audit_log
WHERE 1 = 1

    AND user_id = #{userId}


    AND operation = #{operationType}


    AND create_time >= #{startTime}


    AND create_time <= #{endTime}

ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM audit_log
WHERE 1 = 1

    AND user_id = #{userId}


    AND operation = #{operationType}


    AND create_time >= #{startTime}


    AND create_time <= #{endTime}
